  ('elementary-10ced7e2-moex-00372', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於普通抵押權之敘述，何者錯誤？', '["抵押權為不移轉占有而供債權擔保之不動產物權，且抵押人得為債務人以外之第三人", "抵押權之效力及於抵押物滅失後之殘餘物，以及非依物之通常用法而分離成為獨立之動產者", "不動產所有人設定地上權後，於同一不動產上仍得設定抵押權，但其抵押權不因此而受影響", "抵押權人於債權清償期屆滿後，為受清償，得訂立契約，取得抵押物之所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00373', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者正確？', '["最高限額抵押權所擔保之債權，於原債權確定前讓與他人者，其最高限額抵押權應隨同移轉", "抵押權人死亡時，最高限額抵押權則當然消滅", "最高限額抵押權所擔保之原債權確定後，其擔保效力原則上不及於其後繼續發生之債權", "最高限額抵押權所擔保之債權，其請求權已因時效而消滅，如抵押權人於消滅時效完成後，五年間不實 行其抵押權者，其抵押權消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00374', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何種情形，鄰地所有人得請求拆除地上物？', '["土地所有人輕過失越界建築立體停車場，而鄰地所有人未即時異議", "普通地上權人輕過失越界建築房屋，而鄰地所有人未即時異議", "土地無權占有人輕過失越界建築納骨塔，而鄰地所有人未即時異議", "土地承租人輕過失越界建築倉庫，而鄰地所有人未即時異議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
